from dataclasses import dataclass, field
from typing import Optional
from enum import Enum

class MetricType(str, Enum):
    STRATEGIC = "strategic"   # business goal — annual horizon
    OUTCOME   = "outcome"     # measurable change in user/business behaviour — monthly
    OUTPUT    = "output"      # AI system behaviour metric — daily/weekly

@dataclass
class GenAIMetric:
    name: str
    metric_type: MetricType
    description: str
    target: str
    measurement_method: str
    cadence: str
    owner: str
    leads_to: Optional[str] = None   # outcome or strategic metric this feeds

    def is_lagging(self) -> bool:
        return self.metric_type in (MetricType.STRATEGIC, MetricType.OUTCOME)

    def is_leading(self) -> bool:
        return self.metric_type == MetricType.OUTPUT

@dataclass
class MetricFramework:
    feature_name: str
    metrics: list[GenAIMetric] = field(default_factory=list)

    def by_type(self, t: MetricType) -> list[GenAIMetric]:
        return [m for m in self.metrics if m.metric_type == t]

    def leading_to(self, outcome_name: str) -> list[GenAIMetric]:
        return [m for m in self.metrics if m.leads_to == outcome_name]

    def validate(self) -> list[str]:
        errors = []
        outputs = self.by_type(MetricType.OUTPUT)
        outcomes = self.by_type(MetricType.OUTCOME)
        for out in outputs:
            if not out.leads_to:
                errors.append(f"Output metric '{out.name}' has no leads_to linkage")
        if not outcomes:
            errors.append("Framework has no outcome metrics — only tracking AI behaviour, not business impact")
        return errors
